mapper.select:
UPDATE outbox_event
SET status = 'PROCESSING', updated_at = now() AT TIME ZONE 'UTC'
WHERE (oeid, created_at) IN (
    SELECT oeid, created_at FROM outbox_event
    WHERE status = 'NEW'
      AND created_at <= #{tSafe, typeHandler=com.dogancaglar.common.db.typehandler.InstantTypeHandler}
    ORDER BY created_at
    LIMIT #{batchSize}
)
RETURNING *;

SELECT COUNT(*) FROM (
    SELECT 1 FROM outbox_event
    WHERE status = 'NEW'
      AND created_at <= #{tSafe, typeHandler=com.dogancaglar.common.db.typehandler.InstantTypeHandler}
    LIMIT 10000
) sub

mapper.update:
UPDATE outbox_event
SET status = 'SENT', updated_at = now() AT TIME ZONE 'UTC'
WHERE oeid = #{oeid} AND created_at = #{createdAt, typeHandler=com.dogancaglar.common.db.typehandler.InstantTypeHandler}
